#include <iostream>
#include <algorithm>
using namespace std;
struct student
{
    string name;
    int year,mouth,day,order;
};
student a[105];
bool cmp(student x,student y)
{
    if(x.year!=y.year)
    {
        return x.year<y.year;
    }
    else if(x.mouth!=y.mouth)
    {
        return x.mouth<y.mouth;
    }
    else if(x.day!=y.day)
    {
        return x.day<y.day;
    }
    else
    {
        return x.order>y.order;
    }
}
int main()
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].name>>a[i].year>>a[i].mouth>>a[i].day;
        a[i].order=i;
    }
    sort(a,a+n,cmp);
    for(int i=0;i<=n-1;i++)
    {
        cout<<a[i].name<<endl;
    }
    return 0;
}
